以下是CUDA kernel启动时返回`cudaErrorInvalidConfiguration`的5个最常见原因及排查顺序：

## 1. **Grid/Block维度配置超出限制**
```cpp
// 错误示例：blockSize过大
dim3 blockSize(1024, 1024, 1); // 超过maxThreadsPerBlock

// 正确做法
int maxThreadsPerBlock;
cudaDeviceGetAttribute(&maxThreadsPerBlock, 
                       cudaDevAttrMaxThreadsPerBlock, 0);
dim3 blockSize(std::min(512, maxThreadsPerBlock), 1, 1);
```

**排查方法：**
- `cudaDeviceGetAttribute(&maxThreadsPerBlock, cudaDevAttrMaxThreadsPerBlock, 0)`
- 检查`(blockDim.x * blockDim.y * blockDim.z) <= maxThreadsPerBlock`

## 2. **共享内存使用量超标**
```cpp
// 检查共享内存限制
size_t sharedMemPerBlock;
cudaDeviceGetAttribute(&sharedMemPerBlock, 
                       cudaDevAttrSharedMemoryPerBlock, 0);

// kernel启动前检查
if (dynamicSharedMemSize > sharedMemPerBlock) {
    printf("共享内存超限: %zu > %zu\n", 
           dynamicSharedMemSize, sharedMemPerBlock);
}
```

## 3. **线程块数超过网格维度限制**
```cpp
// 检查最大grid尺寸
int maxGridX, maxGridY, maxGridZ;
cudaDeviceGetAttribute(&maxGridX, cudaDevAttrMaxGridDimX, 0);
cudaDeviceGetAttribute(&maxGridY, cudaDevAttrMaxGridDimY, 0);
cudaDeviceGetAttribute(&maxGridZ, cudaDevAttrMaxGridDimZ, 0);

// 确保gridDim在限制内
if (gridDim.x > maxGridX || gridDim.y > maxGridY || gridDim.z > maxGridZ) {
    // 调整配置
}
```

## 4. **寄存器使用量过高导致活动线程数不足**
```cpp
// 编译时查看寄存器使用情况
// nvcc -Xptxas -v your_file.cu

// 运行时设置最大占用率
cudaFuncSetAttribute(kernel_func, 
                     cudaFuncAttributeMaxDynamicSharedMemorySize, 
                     required_shared_mem);

// 或者限制每个block的线程数
int minGridSize, blockSize;
cudaOccupancyMaxPotentialBlockSize(&minGridSize, &blockSize, 
                                   kernel_func, 0, 0);
```

## 5. **设备能力不匹配或参数错误**
```cpp
// 获取设备计算能力
cudaDeviceProp prop;
cudaGetDeviceProperties(&prop, 0);
printf("Compute Capability: %d.%d\n", prop.major, prop.minor);

// 检查设备是否支持
if (prop.major < 2) {  // 某些功能需要CC >= 2.0
    printf("设备计算能力不足\n");
}

// 验证kernel参数指针有效性
cudaPointerAttributes attr;
cudaPointerGetAttributes(&attr, device_ptr);
if (attr.type == cudaMemoryTypeUnregistered) {
    printf("无效的设备指针\n");
}
```

## **推荐排查顺序：**

1. **先检查显式限制**：block size、grid size是否超出硬件限制
2. **验证资源使用**：共享内存、寄存器使用量
3. **确认设备兼容性**：计算能力和驱动版本
4. **运行时调试**：逐步减小配置规模定位问题
5. **代码审查**：kernel参数传递是否正确

**
